/**
 * OrionFab — reusable floating-action-button trigger for the Orion bottom
 * sheet. Reads unread-task count + sheet visibility from OrionContext, so
 * pages don't have to plumb those signals themselves. Drop one anywhere on
 * an authenticated route.
 *
 * Two layout variants:
 *  - 'fixed' (default): position: fixed, bottom-right of the viewport.
 *  - 'sticky': position: sticky inside its parent — used by TradeCalendarPage
 *    so the FAB shifts inward when the right SidePanel opens (parent is the
 *    flex: 1 left content column).
 */
import React from 'react';
import { Box, Fab, Tooltip, Badge, alpha, useTheme } from '@mui/material';
import { SmartToy as AIIcon } from '@mui/icons-material';
import { useOrion } from '../../contexts/OrionContext';

export interface OrionFabProps {
  /** Layout mode. Default 'fixed'. */
  variant?: 'fixed' | 'sticky';
  /** Hide the FAB. Useful while a different drawer/dialog covers the screen. */
  hidden?: boolean;
}

const OrionFab: React.FC<OrionFabProps> = ({ variant = 'fixed', hidden = false }) => {
  const theme = useTheme();
  const { open, unreadCount } = useOrion();

  if (hidden) return null;

  const hasUnread = (unreadCount ?? 0) > 0;

  return (
    <Box
      sx={
        variant === 'fixed'
          ? {
              position: 'fixed',
              bottom: { xs: 16, sm: 24 },
              right: { xs: 16, sm: 24 },
              zIndex: 50,
              pointerEvents: 'none',
            }
          : {
              position: 'sticky',
              bottom: { xs: 16, sm: 24 },
              display: 'flex',
              justifyContent: 'flex-end',
              pr: { xs: 2, sm: 3 },
              pointerEvents: 'none',
              zIndex: 50,
            }
      }
    >
      <Tooltip title="Orion" placement="left">
        <Fab
          aria-label="open orion chat"
          onClick={() => open()}
          color="secondary"
          size="medium"
          sx={{
            pointerEvents: 'auto',
            width: { xs: 48, sm: 56 },
            height: { xs: 48, sm: 56 },
            '&:hover': { transform: 'scale(1.08)' },
            transition: 'transform 0.2s ease',
            // Pulse a soft ring around the FAB when there's an unread briefing.
            // Box-shadow is layout-neutral and stacks cleanly with the hover
            // scale transform above.
            ...(hasUnread && {
              animation: 'orionFabPulse 1.8s ease-out infinite',
              '@keyframes orionFabPulse': {
                '0%': {
                  boxShadow: `0 0 0 0 ${alpha(theme.palette.secondary.main, 0.55)}`,
                },
                '70%': {
                  boxShadow: `0 0 0 14px ${alpha(theme.palette.secondary.main, 0)}`,
                },
                '100%': {
                  boxShadow: `0 0 0 0 ${alpha(theme.palette.secondary.main, 0)}`,
                },
              },
            }),
          }}
        >
          <Badge
            variant="dot"
            color="error"
            invisible={!hasUnread}
            sx={{
              '& .MuiBadge-badge': {
                top: 4,
                right: 4,
                width: 10,
                height: 10,
                borderRadius: '50%',
              },
            }}
          >
            <AIIcon />
          </Badge>
        </Fab>
      </Tooltip>
    </Box>
  );
};

export default OrionFab;
